import { methods } from "@neuraiproject/neurai-rpc";
export async function getAssets(wallet, addresses) {
    const includeAssets = true;
    const params = [{ addresses: addresses }, includeAssets];
    const balance = (await wallet.rpc(methods.getaddressbalance, params));
    //Remove baseCurrency
    //Convert from satoshis
    const result = balance.filter((obj) => {
        obj.assetName !== wallet.baseCurrency;
        obj.value = 0;
        if (obj.balance > 0) {
            obj.value = obj.balance / 1e8;
        }
        return obj;
    });
    return result;
}
